import React from "react";
import { NavLink } from "react-router-dom";
import "./Navbar.css";

function Navbar() {
  return (
    <nav className="navbar">
      <h1 className="navbar-logo">Quản Lý Tiền</h1>
      <ul className="navbar-links">
        <li><NavLink to="/login" activeClassName="active">Đăng nhập</NavLink></li>
        <li><NavLink to="/register" activeClassName="active">Đăng ký</NavLink></li>
        <li><NavLink to="/dashboard" activeClassName="active">Dashboard</NavLink></li>
        <li><NavLink to="/budgets" activeClassName="active">Ngân sách</NavLink></li>
        <li><NavLink to="/categories" activeClassName="active">Danh mục</NavLink></li>
        <li><NavLink to="/goals" activeClassName="active">Mục tiêu</NavLink></li>
        <li><NavLink to="/transactions" activeClassName="active">Giao dịch</NavLink></li>
        <li><NavLink to="/transfers" activeClassName="active">Chuyển tiền</NavLink></li>
      </ul>
    </nav>
  );
}

export default Navbar;
